    f.ZIndex = 40
    f.Parent = ScreenGui
    corner(f, Theme.Rounded)
    stroke(f, Theme.Stroke, 1, 0.2)
    self._frame = f
    task.delay(8, function()
        if self._frame and self.Enabled then
            tween(self._frame, 1, { BackgroundTransparency = 1, TextTransparency = 1 })
