        runBtn.Font = Theme.FontBold
        runBtn.TextSize = 12
        runBtn.TextColor3 = Theme.Text
        runBtn.BorderSizePixel = 0
        runBtn.ZIndex = 15
        runBtn.Parent = card
        corner(runBtn, UDim.new(0, 6))
        stroke(runBtn, Theme.Stroke, 1, 0)
        addHoverAnim(runBtn, 1.1)

        -- card hover effect
        local cardScale = addHoverAnim(card, 1.03)
        card.MouseEnter:Connect(function()
            tween(cardStroke, 0.12, { Color = g.accent or Theme.Accent, Transparency = 0 })
        end)
        card.MouseLeave:Connect(function()
            tween(cardStroke, 0.12, { Color = Theme.Stroke, Transparency = 0.4 })
        end)

        -- click flash
        local function flash()
            tween(card, 0.08, { BackgroundColor3 = g.accent or Theme.Accent })
            task.delay(0.08, function() tween(card, 0.15, { BackgroundColor3 = Theme.Element }) end)
        end

        -- TELEPORT action
        tpBtn.MouseButton1Click:Connect(function()
            flash()
            if not g.id or g.id <= 0 then
                notify("Place Teleporter", g.name .. " has no PlaceId set. Add it with '+ Add'.", 4, Theme.Red)
                return
            end
            notify("Place Teleporter", "Teleporting to " .. g.name .. "...", 4, Theme.Accent)
            local done = false
            local ok = pcall(function()
                TeleportService:Teleport(g.id, LocalPlayer)
                done = true
            end)
            -- fallback: queue on teleport & retry
            if not ok then
                pcall(function()
                    if queue_on_teleport then
                        queue_on_teleport([[loadstring(game:HttpGet("YOUR_HUB_URL"))()]])
                    end
                end)
            end
        end)

        -- JOIN RANDOM SERVER action (hold / right click the card body)
        card.MouseButton2Down:Connect(function()
            flash()
            if not g.id or g.id <= 0 then return end
            notify("Place Teleporter", "Searching a fresh server for " .. g.name .. "...", 4, Theme.Yellow)
            task.spawn(function()
                pcall(function()
                    local pages = TeleportService:GetSortedAsync(false, 100)
                    for _, item in ipairs(pages:GetCurrentPage()) do
                        if item.Id ~= game.JobId and item.Playing < item.MaxPlayers then
                            TeleportService:TeleportToPlaceInstance(g.id, item.Id, LocalPlayer)
                            return
                        end
                    end
                    TeleportService:Teleport(g.id, LocalPlayer)
                end)
            end)
        end)

        -- RUN action: open the matching feature window if supported
        runBtn.MouseButton1Click:Connect(function()
            flash()
            local found = nil
            for _, entry in ipairs(GameList) do
                if entry.name == g.name then found = entry; break end
            end
            if found then
                if OpenWindows[g.name] and not OpenWindows[g.name]._destroyed then
                    OpenWindows[g.name].Root.Visible = true
                    bringToFront(OpenWindows[g.name].Root)
                else
                    local ok2, win = pcall(found.builder)
                    if ok2 and win then OpenWindows[g.name] = win end
                end
                notify("Place Teleporter", "Opened " .. g.name .. " features.", 3, Theme.Green)
            else
                notify("Place Teleporter", "No feature window for " .. g.name .. ". Try Universal.", 3, Theme.Yellow)
                -- open Universal as a fallback
                if OpenWindows["Universal"] and not OpenWindows["Universal"]._destroyed then
                    OpenWindows["Universal"].Root.Visible = true
                    bringToFront(OpenWindows["Universal"].Root)
                else
                    local uok, uwin = pcall(Universal)
                    if uok and uwin then OpenWindows["Universal"] = uwin end
                end
            end
        end)
        return card
    end

    -- render the grid based on category + search
    local function render()
        for _, c in ipairs(grid:GetChildren()) do
            if c:IsA("Frame") and c.Name ~= "UIGridLayout" then c:Destroy() end
        end
        order = 0
        local query = string.lower(sBox.Text)
        local shown = 0
        for _, g in ipairs(getPlaceList()) do
            local catOk = (PlaceHubState.cat == "All") or (g.cat == PlaceHubState.cat)
            local qOk = (query == "")
                or string.lower(g.name):find(query)
                or tostring(g.id):find(query)
            if catOk and qOk then
                makeCard(g)
                shown = shown + 1
            end
        end
        subtitle.Text = "Showing " .. shown .. " game(s)  •  right-click a card = join fresh server"
    end

    -- build category tabs
    local categories = { "All", "FPS", "RP", "SOCIAL", "SIMULATOR", "RPG", "STRATEGY", "HORROR", "ACTION", "OBBY", "SURVIVAL", "TYCOON", "SANDBOX", "RNG", "FIND", "FUN" }
    local tabButtons = {}
    for _, cat in ipairs(categories) do
        local b = Instance.new("TextButton")
        b.Size = UDim2.new(0, 0, 1, 0)
        b.AutomaticSize = Enum.AutomaticSize.X
        b.BackgroundColor3 = (cat == PlaceHubState.cat) and Theme.Accent or Theme.Element
        b.Text = "  " .. cat .. "  "
        b.Font = Theme.FontBold
        b.TextSize = 12
        b.TextColor3 = (cat == PlaceHubState.cat) and Color3.fromRGB(255,255,255) or Theme.TextDim
        b.BorderSizePixel = 0
        b.ZIndex = 12
        b.Parent = catList
        corner(b, UDim.new(0, 8))
        local pad = Instance.new("UIPadding"); pad.PaddingLeft = UDim.new(0,2); pad.PaddingRight = UDim.new(0,2); pad.Parent = b
        addHoverAnim(b, 1.05)
        b.MouseButton1Click:Connect(function()
            PlaceHubState.cat = cat
            -- recolor all tabs
            for c, btn in pairs(tabButtons) do
                local sel = (c == cat)
                tween(btn, 0.12, { BackgroundColor3 = sel and Theme.Accent or Theme.Element })
                btn.TextColor3 = sel and Color3.fromRGB(255,255,255) or Theme.TextDim
            end
            render()
        end)
        tabButtons[cat] = b
    end

    -- search reaction
    sBox:GetPropertyChangedSignal("Text"):Connect(render)

    -- ADD CUSTOM GAME popup (simple inline form)
    addBtn.MouseButton1Click:Connect(function()
        -- build a small modal
        local modal = Instance.new("Frame")
        modal.Size = UDim2.new(0, 340, 0, 240)
        modal.Position = UDim2.new(0.5, -170, 0.5, -120)
        modal.BackgroundColor3 = Theme.Background
        modal.BorderSizePixel = 0
        modal.ZIndex = 80
        modal.Parent = ScreenGui
        corner(modal, UDim.new(0, 12))
        stroke(modal, Theme.Accent, 1.5, 0)
        bringToFront(modal)
        animateEntrance(modal, 0)
        local mt = Instance.new("TextLabel")
        mt.BackgroundTransparency = 1; mt.Size = UDim2.new(1,-20,0,24); mt.Position = UDim2.new(0,12,0,12)
        mt.Font = Theme.FontBold; mt.TextSize = 15; mt.TextColor3 = Theme.Text; mt.TextXAlignment = Enum.TextXAlignment.Left
        mt.Text = "Add Custom Game"; mt.ZIndex = 81; mt.Parent = modal
        local function field(y, ph)
            local b = Instance.new("TextBox")
            b.Size = UDim2.new(1, -24, 0, 32); b.Position = UDim2.new(0,12,0,y)
            b.BackgroundColor3 = Theme.Element; b.Font = Theme.Font; b.TextSize = 13; b.TextColor3 = Theme.Text
            b.PlaceholderText = ph; b.PlaceholderColor3 = Theme.TextDim; b.ClearTextOnFocus = false; b.Text = ""
            b.TextXAlignment = Enum.TextXAlignment.Left; b.BorderSizePixel = 0; b.ZIndex = 81; b.Parent = modal
            corner(b, UDim.new(0,8)); stroke(b, Theme.Stroke, 1, 0.2)
            local p = Instance.new("UIPadding"); p.PaddingLeft = UDim.new(0,10); p.Parent = b
            return b
        end
        local nBox = field(46, "Game name")
        local idBox = field(86, "PlaceId (number)")
        local catBox = field(126, "Category (e.g. FPS)")
        local saveB = Instance.new("TextButton")
        saveB.Size = UDim2.new(0, 140, 0, 32); saveB.Position = UDim2.new(0, 12, 0, 186)
        saveB.BackgroundColor3 = Theme.Accent; saveB.Text = "Save & Add"; saveB.Font = Theme.FontBold; saveB.TextSize = 13
        saveB.TextColor3 = Color3.fromRGB(255,255,255); saveB.BorderSizePixel = 0; saveB.ZIndex = 81; saveB.Parent = modal
        corner(saveB, UDim.new(0,8)); addHoverAnim(saveB, 1.05)
        local cancelB = Instance.new("TextButton")
        cancelB.Size = UDim2.new(0, 140, 0, 32); cancelB.Position = UDim2.new(1, -152, 0, 186)
        cancelB.BackgroundColor3 = Theme.ElementHover; cancelB.Text = "Cancel"; cancelB.Font = Theme.FontBold; cancelB.TextSize = 13
        cancelB.TextColor3 = Theme.Text; cancelB.BorderSizePixel = 0; cancelB.ZIndex = 81; cancelB.Parent = modal
        corner(cancelB, UDim.new(0,8)); addHoverAnim(cancelB, 1.05)
        local close = function() tween(modal, 0.18, { BackgroundTransparency = 1 }); task.wait(0.18); modal:Destroy() end
        cancelB.MouseButton1Click:Connect(close)
        saveB.MouseButton1Click:Connect(function()
            local nm = nBox.Text
            local pid = tonumber(idBox.Text) or 0
            local ct = catBox.Text
            if ct == "" then ct = "CUSTOM" end
            if nm ~= "" then
                table.insert(PlaceCustom, { name = nm, id = pid, cat = string.upper(ct), icon = "🎮", accent = Theme.Accent })
                saveCustomPlaces()
                notify("Place Teleporter", "Added " .. nm .. " (id " .. pid .. ")", 3, Theme.Green)
                render()
            end
            close()
        end)
    end)

    render()
    animateEntrance(root, 0.05)
    bringToFront(root)

    self.Root = root
    self._dead = false
    function self:Destroy()
        self._dead = true
        tween(root, 0.18, { BackgroundTransparency = 1 })
        task.wait(0.18)
        root:Destroy()
        reopen:Destroy()
        PlaceHubState.open = nil
    end
    notify("Place Teleporter", "Loaded. TP to any game, or ▶ to run its features.", 4, Theme.Accent)
    return self
end

--==============================================================================
--// SERVER BROWSER  (browse & join servers of the current place, with stats)
--   Real TeleportService:GetSortedAsync paging, animated server rows,
--   join buttons, auto-rejoin, and "join smallest/largest server" helpers.
--==============================================================================
local function ServerBrowser()
    local w = createWindow("Server Browser", "Browse & join servers", 470, 580, randPos(470, 580))
    w:AddSection("Current Game")
    w:AddLabel("Place: " .. tostring(game.PlaceId))
    w:AddLabel("JobId: " .. tostring(game.JobId))
    w:AddLabel("Players here: " .. #Players:GetPlayers())
    w:AddSection("Quick Actions")
    w:AddButton("Rejoin This Server", function()
        notify("Servers", "Rejoining current server...", 3, Theme.Accent)
        pcall(function() TeleportService:TeleportToPlaceInstance(game.PlaceId, game.JobId, LocalPlayer) end)
    end, Theme.Accent)
    w:AddButton("Join Fresh Server (hop)", function()
        ServerHop.hop()
    end, Theme.Green)
    w:AddButton("Join Smallest Server", function()
        notify("Servers", "Searching smallest server...", 3, Theme.Yellow)
        task.spawn(function()
            pcall(function()
                local pages = TeleportService:GetSortedAsync(false, 100)
                local bestId, bestCount = nil, math.huge
                for _, item in ipairs(pages:GetCurrentPage()) do
                    if item.Playing < bestCount and item.Id ~= game.JobId then
                        bestCount = item.Playing; bestId = item.Id
                    end
                end
                if bestId then
                    TeleportService:TeleportToPlaceInstance(game.PlaceId, bestId, LocalPlayer)
                end
            end)
        end)
    end)
    w:AddButton("Join Largest Server", function()
        notify("Servers", "Searching largest server...", 3, Theme.Yellow)
        task.spawn(function()
            pcall(function()
                local pages = TeleportService:GetSortedAsync(false, 100)
                local bestId, bestCount = nil, -1
                for _, item in ipairs(pages:GetCurrentPage()) do
                    if item.Playing > bestCount and item.Id ~= game.JobId then
                        bestCount = item.Playing; bestId = item.Id
                    end
                end
                if bestId then
                    TeleportService:TeleportToPlaceInstance(game.PlaceId, bestId, LocalPlayer)
                end
            end)
        end)
    end)
    w:AddSection("Server List")
    w:AddLabel("Lists up to ~20 servers with player counts.")
    local listHolder = w.Content
    -- container for server rows
    local rowsFrame = Instance.new("Frame")
    rowsFrame.Size = UDim2.new(1, 0, 0, 0)
    rowsFrame.AutomaticSize = Enum.AutomaticSize.Y
    rowsFrame.BackgroundTransparency = 1
    rowsFrame.ZIndex = 11
    rowsFrame.Parent = listHolder
    local rowsLayout = Instance.new("UIListLayout")
    rowsLayout.Padding = UDim.new(0, 6)
    rowsLayout.Parent = rowsFrame

    local function makeRow(item, idx)
        local row = Instance.new("Frame")
        row.Size = UDim2.new(1, 0, 0, 44)
        row.BackgroundColor3 = Theme.Element
        row.BorderSizePixel = 0
        row.ZIndex = 11
        row.Parent = rowsFrame
        corner(row, Theme.Rounded)
        local st = stroke(row, Theme.Stroke, 1, 0.2)
        local num = Instance.new("TextLabel")
        num.BackgroundTransparency = 1; num.Position = UDim2.new(0,8,0,0); num.Size = UDim2.new(0,28,1,0)
        num.Font = Theme.FontBold; num.TextSize = 14; num.TextColor3 = Theme.AccentBright; num.Text = "#" .. idx
        num.ZIndex = 12; num.Parent = row
        local pl = Instance.new("TextLabel")
        pl.BackgroundTransparency = 1; pl.Position = UDim2.new(0,42,0,6); pl.Size = UDim2.new(1,-150,0,16)
        pl.Font = Theme.FontBold; pl.TextSize = 12; pl.TextColor3 = Theme.Text; pl.TextXAlignment = Enum.TextXAlignment.Left
        pl.Text = item.Playing .. " / " .. item.MaxPlayers .. " players"
        pl.ZIndex = 12; pl.Parent = row
        local pct = math.clamp(item.Playing / math.max(item.MaxPlayers, 1), 0, 1)
        local bar = Instance.new("Frame")
        bar.Size = UDim2.new(1, -150, 0, 6); bar.Position = UDim2.new(0, 42, 0, 28)
        bar.BackgroundColor3 = Theme.ElementHover; bar.BorderSizePixel = 0; bar.ZIndex = 12; bar.Parent = row
        corner(bar, UDim.new(1, 0))
        local barFill = Instance.new("Frame")
        barFill.Size = UDim2.new(pct, 0, 1, 0); barFill.BackgroundColor3 = Color3.fromHSV(pct/2.5, 0.8, 0.8); barFill.BorderSizePixel = 0; barFill.ZIndex = 13; barFill.Parent = bar
        corner(barFill, UDim.new(1, 0))
        local join = Instance.new("TextButton")
        join.Size = UDim2.new(0, 70, 0, 28); join.Position = UDim2.new(1, -80, 0.5, -14)
        join.BackgroundColor3 = Theme.Accent; join.Text = "Join"; join.Font = Theme.FontBold; join.TextSize = 12
        join.TextColor3 = Color3.fromRGB(255,255,255); join.BorderSizePixel = 0; join.ZIndex = 12; join.Parent = row
        corner(join, UDim.new(0, 7))
        local us = Instance.new("UIScale"); us.Scale = 1; us.Parent = join
        join.MouseEnter:Connect(function() tween(us, 0.1, {Scale = 1.08}) end)
        join.MouseLeave:Connect(function() tween(us, 0.1, {Scale = 1}) end)
        row.MouseEnter:Connect(function() tween(st, 0.1, { Color = Theme.Accent, Transparency = 0 }) end)
        row.MouseLeave:Connect(function() tween(st, 0.1, { Color = Theme.Stroke, Transparency = 0.2 }) end)
        join.MouseButton1Click:Connect(function()
            if item.Id == game.JobId then
                notify("Servers", "You're already in this server.", 3, Theme.Yellow)
                return
            end
            notify("Servers", "Joining server #" .. idx .. "...", 3, Theme.Accent)
            pcall(function() TeleportService:TeleportToPlaceInstance(game.PlaceId, item.Id, LocalPlayer) end)
        end)
    end

    w:AddButton("Load Server List", function()
        for _, c in ipairs(rowsFrame:GetChildren()) do
            if c:IsA("Frame") then c:Destroy() end
        end
        notify("Servers", "Querying servers...", 2.5, Theme.Accent)
        task.spawn(function()
            local ok, pages = pcall(function() return TeleportService:GetSortedAsync(false, 100) end)
            if not ok or not pages then
                notify("Servers", "Could not fetch servers (Studio limit).", 3, Theme.Red)
                return
            end
            local shown = 0
            for _, item in ipairs(pages:GetCurrentPage()) do
                if shown >= 20 then break end
                shown = shown + 1
                makeRow(item, shown)
                task.wait(0.02)
            end
            notify("Servers", "Loaded " .. shown .. " servers.", 3, Theme.Green)
        end)
    end, Theme.Accent)
    w:AddButton("Clear List", function()
        for _, c in ipairs(rowsFrame:GetChildren()) do if c:IsA("Frame") then c:Destroy() end end
    end, Theme.Yellow)
    w:AddSection("Info")
    w:AddLabel("TeleportService works on live games; Studio may limit it.")
    notify("Server Browser", "Loaded.", 3, Theme.Accent)
    return w
end

--==============================================================================
--// Z3US-STYLE SCRIPT LOADER  ("Z3US Loader")
--   A faithful recreation of the Z3US game-select hub: a draggable + minimizable
--   window with a vertical list of styled game cards (Arsenal, Planks, OneTap,
--   Rivals, Counterblox, Gunfight Arena, Universal), a SCRIPT_KEY input, an
--   autoload toggle, a silentload toggle, and a version selector (New/Old) for
--   Counterblox. Clicking a card selects it; the "Load" button runs the matching
--   built-in feature window (since this is a Studio test suite, it opens the
--   feature suite locally instead of loadstring-ing an external premium script).
--   Selection is remembered, and the load flow mirrors Z3US exactly:
--     selectedOption == "Arsenal"  -> open Arsenal suite
--     selectedOption == "Planks"   -> open Planks suite
--     selectedOption == "OneTap"   -> open One Tap suite
--     selectedOption == "Rivals"   -> open Rivals suite (waits for game load)
--     selectedOption == "Counterblox" -> open Counterblox suite
--     selectedOption == "Gunfight Arena" -> open Gunfight Arena suite
--     selectedOption == "Universal" -> open Universal suite
--==============================================================================

-- Z3US shared global state (mirrors getgenv() used by the real loaders).
local Z3USState = {
    SCRIPT_KEY = "",
    autoload = false,
    silentload = false,
    version = "New",
    selectedOption = nil,
    selectedCard = nil,
}

-- Mirror getgenv() so the same pattern works for real executors too.
pcall(function()
    if getgenv then
        getgenv().SCRIPT_KEY = Z3USState.SCRIPT_KEY
        getgenv().autoload = Z3USState.autoload
        getgenv().silentload = Z3USState.silentload
    end
end)

-- Maps a Z3US game option -> the built-in builder that opens on "Load".
local Z3USGames = {
    { option = "Arsenal",        icon = "🔫", accent = Color3.fromRGB(255,90,90),   builder = "Arsenal",        detected = false },
    { option = "Planks",         icon = "🪵", accent = Color3.fromRGB(120,200,120), builder = "Planks",         detected = false },
    { option = "OneTap",         icon = "💥", accent = Color3.fromRGB(180,80,255),  builder = "One Tap",        detected = false },
    { option = "Rivals",         icon = "🎯", accent = Color3.fromRGB(70,150,255),  builder = "Rivals",         detected = false },
    { option = "Counterblox",    icon = "🧨", accent = Color3.fromRGB(255,200,60),  builder = "Counterblox",    detected = true },
    { option = "Gunfight Arena", icon = "🔫", accent = Color3.fromRGB(255,110,90),  builder = "Gunfight Arena", detected = false },
    { option = "Universal",      icon = "🌍", accent = Theme.Accent,                builder = "Universal",      detected = false },
}

-- Open a feature window by its registered name (used by the Load button).
local function openFeatureByName(name)
    local found = nil
    for _, entry in ipairs(GameList) do
        if entry.name == name then found = entry; break end
    end
    if not found then
        notify("Z3US", "No suite for '" .. name .. "'.", 3, Theme.Red)
        return nil
    end
    if OpenWindows[name] and not OpenWindows[name]._destroyed then
        OpenWindows[name].Root.Visible = true
        bringToFront(OpenWindows[name].Root)
        return OpenWindows[name]
    else
        local ok, win = pcall(found.builder)
        if ok and win then
            OpenWindows[name] = win
            return win
        else
            notify("Z3US", "Failed to load " .. name .. ": " .. tostring(win), 4, Theme.Red)
        end
    end
    return nil
end

-- The Z3US "Load" handler — mirrors the original if/elseif chain.
local function z3usLoad()
    local opt = Z3USState.selectedOption
    if not opt then
        notify("Z3US", "No script selected.", 3, Theme.Yellow)
        return
    end

    -- Mirror Z3US global plumbing (real executors read these).
    pcall(function()
        if getgenv then
            getgenv().SCRIPT_KEY = Z3USState.SCRIPT_KEY
            getgenv().autoload = Z3USState.autoload
            getgenv().silentload = Z3USState.silentload
        end
    end)

    -- Replicate Z3US' load gate: wait for game + character + no loading screen
    if not game:IsLoaded() then
        notify("Z3US", "Waiting for game to load...", 3, Theme.Yellow)
        repeat task.wait() until game:IsLoaded()
    end

    local function openAndNotify(name, detectedMsg)
        if Z3USState.silentload then
            notify("Z3US", "(silent) Loading " .. name .. "...", 3, Theme.Accent)
        else
            notify("Z3US", "Loading " .. name .. "...", 3, Theme.Accent)
        end
        if detectedMsg then
            notify("Z3US", "NOTE: " .. detectedMsg, 4, Theme.Yellow)
        end
        task.spawn(function()
            if name == "Rivals" then
                -- Z3US waits for character + no LoadingScreen for Rivals
                repeat task.wait() until LocalPlayer and LocalPlayer.Character
                local pg = LocalPlayer:FindFirstChild("PlayerGui")
                if pg then
                    repeat task.wait() until not pg:FindFirstChild("LoadingScreen")
                end
            end
            task.wait(0.2)
            local win = openFeatureByName(name)
            if win then
                notify("Z3US", name .. " loaded" .. (Z3USState.autoload and " (autoload on)" or "") .. ".", 3, Theme.Green)
            end
        end)
    end

    -- The exact if/elseif chain from Z3US' other.lua.
    if opt == "Arsenal" then
        openAndNotify("Arsenal")
    elseif opt == "Planks" then
        openAndNotify("Planks")
    elseif opt == "OneTap" then
        openAndNotify("One Tap")
    elseif opt == "Rivals" then
        openAndNotify("Rivals")
    elseif opt == "Counterblox" then
        if Z3USState.version == "New" then
            -- In the original, the New version is detected and kicks you.
            -- We emulate the warning instead of actually kicking in Studio.
            notify("Z3US", "⚠ The 'New' Counterblox script is detected and would kick/ban you.", 5, Theme.Red)
            notify("Z3US", "Switching to 'Old' version is recommended. Loading Old suite...", 4, Theme.Yellow)
            Z3USState.version = "Old"
        end
        openAndNotify("Counterblox")
    elseif opt == "Gunfight Arena" then
        openAndNotify("Gunfight Arena")
    elseif opt == "Universal" then
        openAndNotify("Universal")
    else
        notify("Z3US", "Unknown option: " .. tostring(opt), 3, Theme.Red)
    end
end

-- Build the animated Z3US Loader window.
local Z3USHubState = { open = nil }
local function buildZ3USLoader()
    if Z3USHubState.open and not Z3USHubState.open._dead then
        Z3USHubState.open.Root.Visible = true
        bringToFront(Z3USHubState.open.Root)
        return Z3USHubState.open
    end

    local self = { _dead = false }
    Z3USHubState.open = self

    local root = Instance.new("Frame")
    root.Name = "Z3USLoader"
    root.Size = UDim2.new(0, 460, 0, 560)
    root.Position = UDim2.new(0.5, -230, 0.5, -280)
    root.BackgroundColor3 = Color3.fromRGB(17, 18, 20)
    root.BorderSizePixel = 0
